import{_ as e,o as l,c as i,ai as r}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"05 小项目：面试笔记总结器（读取 docs/ 下 Markdown）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-1-llm/05-mini-project-notes-summarizer.md","filePath":"ai/stage-1-llm/05-mini-project-notes-summarizer.md"}'),o={name:"ai/stage-1-llm/05-mini-project-notes-summarizer.md"};function t(s,a,n,d,c,m){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="_05-小项目-面试笔记总结器-读取-docs-下-markdown" tabindex="-1">05 小项目：面试笔记总结器（读取 docs/ 下 Markdown） <a class="header-anchor" href="#_05-小项目-面试笔记总结器-读取-docs-下-markdown" aria-label="Permalink to “05 小项目：面试笔记总结器（读取 docs/ 下 Markdown）”">​</a></h1><blockquote><p>目标：做出一个你“马上用得上”的小工具：把某篇笔记总结成固定模板，并输出为新的 Markdown 文件。</p></blockquote><h2 id="_1-功能定义-不要贪多" tabindex="-1">1）功能定义（不要贪多） <a class="header-anchor" href="#_1-功能定义-不要贪多" aria-label="Permalink to “1）功能定义（不要贪多）”">​</a></h2><ul><li>输入：一个 Markdown 文件路径（比如你 VitePress 的某篇文档）</li><li>输出：一个新的 Markdown（总结版），包含： <ul><li>5 点要点</li><li>3 个面试追问</li><li>3 个易错点</li><li>1 段“口语化回答模板”</li></ul></li></ul><h2 id="_2-实现步骤" tabindex="-1">2）实现步骤 <a class="header-anchor" href="#_2-实现步骤" aria-label="Permalink to “2）实现步骤”">​</a></h2><h3 id="第一步-读取文件内容" tabindex="-1">第一步：读取文件内容 <a class="header-anchor" href="#第一步-读取文件内容" aria-label="Permalink to “第一步：读取文件内容”">​</a></h3><ul><li>用 Python 读取 Markdown 文本（注意编码 UTF-8）</li></ul><h3 id="第二步-拼-prompt-固定模板" tabindex="-1">第二步：拼 Prompt（固定模板） <a class="header-anchor" href="#第二步-拼-prompt-固定模板" aria-label="Permalink to “第二步：拼 Prompt（固定模板）”">​</a></h3><ul><li>system：固定输出模板、口吻、边界（不编造、只基于输入）</li><li>user：贴入原文内容</li></ul><h3 id="第三步-调用-llm-api" tabindex="-1">第三步：调用 LLM API <a class="header-anchor" href="#第三步-调用-llm-api" aria-label="Permalink to “第三步：调用 LLM API”">​</a></h3><ul><li>控制输出为 Markdown</li></ul><h3 id="第四步-落盘到-outputs" tabindex="-1">第四步：落盘到 outputs/ <a class="header-anchor" href="#第四步-落盘到-outputs" aria-label="Permalink to “第四步：落盘到 outputs/”">​</a></h3><ul><li>文件名可以按原文件名 + <code>-summary.md</code></li></ul><h2 id="_3-验收标准-做到就算过关" tabindex="-1">3）验收标准（做到就算过关） <a class="header-anchor" href="#_3-验收标准-做到就算过关" aria-label="Permalink to “3）验收标准（做到就算过关）”">​</a></h2><ul><li>你可以对 <code>docs/resume/skills-interview-prep.md</code> 的某一小节做总结</li><li>生成结果是可读、可直接复制到面试回答里的</li></ul>',15)])])}const p=e(o,[["render",t]]);export{u as __pageData,p as default};
